function CustomEdit(&$values, $where, &$oldvalues, &$keys, &$error, $inline, $pageObject)
{

		/******************************************************************************************
 * EVENTO: Custom record update (Edit Page)
 * MÓDULO: Permisos de Funcionarios (RRHH)
 *
 * DESCRIPCIÓN GENERAL:
 * Este evento se ejecuta cuando el usuario edita un registro de permisos
 * y presiona el botón "Guardar".
 *
 * Se utiliza este evento para:
 *  - Tomar control total del proceso de actualización
 *  - Ejecutar manualmente el UPDATE sobre la tabla permisos_funcionarios
