																									WHERE id = ':16'",
																										$values["tipo_vinculacion"],
																										$values["dependencia_id"],
																										$values["fecha_desde"],
																										$values["hora_desde"],
																										$values["fecha_hasta"],
																										$values["hora_hasta"],
																										$values["motivo_id"],
																										$values["comision_servicios"],
																										$values["comision_servicios_descripcion"],
																										$values["observacion"],
																										now(),
																										$values["archivo_adjunto"],
